def set_run_font(run, size=12, bold=False):
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(size)
    run.bold = bold


def add_page_number(paragraph):
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = paragraph.add_run()
    fld_char_begin = OxmlElement("w:fldChar")
    fld_char_begin.set(qn("w:fldCharType"), "begin")
    instr_text = OxmlElement("w:instrText")
    instr_text.set(qn("xml:space"), "preserve")
    instr_text.text = " PAGE "
    fld_char_separate = OxmlElement("w:fldChar")
    fld_char_separate.set(qn("w:fldCharType"), "separate")
    fld_char_end = OxmlElement("w:fldChar")
    fld_char_end.set(qn("w:fldCharType"), "end")
    run._r.append(fld_char_begin)
    run._r.append(instr_text)
    run._r.append(fld_char_separate)
    run._r.append(fld_char_end)


def add_body_paragraph(doc, text, first_indent=True):
    paragraph = doc.add_paragraph()
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    paragraph.paragraph_format.first_line_indent = Cm(1.25) if first_indent else Cm(0)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(0)
    paragraph.paragraph_format.space_after = Pt(0)
    run = paragraph.add_run(text)
    set_run_font(run, 12, False)
    return paragraph


def add_heading(doc, text, main=False):
    paragraph = doc.add_paragraph()
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER if main else WD_ALIGN_PARAGRAPH.LEFT
    paragraph.paragraph_format.first_line_indent = Cm(0)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(0 if main else 12)
    paragraph.paragraph_format.space_after = Pt(12)
    run = paragraph.add_run(text)
    set_run_font(run, 14 if main else 12, True)
    return paragraph


def add_list_item(doc, number, text):
    return add_body_paragraph(doc, f"{number}. {text}")


def add_table_title(doc, text):
    paragraph = doc.add_paragraph()
    paragraph.alignment = WD_ALIGN_PARAGRAPH.LEFT
    paragraph.paragraph_format.first_line_indent = Cm(0)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(12)
    paragraph.paragraph_format.space_after = Pt(6)
    run = paragraph.add_run(text)
    set_run_font(run, 12, False)


def format_cell(cell, text, bold=False):
    cell.text = ""
    paragraph = cell.paragraphs[0]
    paragraph.alignment = WD_ALIGN_PARAGRAPH.LEFT
    paragraph.paragraph_format.line_spacing = 1.0
    run = paragraph.add_run(text)
    set_run_font(run, 10, bold)


def build_document():
    document = Document()
    section = document.sections[0]
    section.top_margin = Cm(2)
    section.bottom_margin = Cm(2)
    section.left_margin = Cm(3)
    section.right_margin = Cm(1.5)

    normal_style = document.styles["Normal"]
    normal_style.font.name = "Times New Roman"
    normal_style._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    normal_style.font.size = Pt(12)

    add_page_number(section.footer.paragraphs[0])

    add_heading(document, "ВВЕДЕНИЕ", main=True)
    for paragraph in INTRO_PARAGRAPHS:
        add_body_paragraph(document, paragraph)
    for index, task in enumerate(INTRO_TASKS, 1):
        add_list_item(document, index, task)
    for paragraph in INTRO_TAIL:
        add_body_paragraph(document, paragraph)

    document.add_page_break()
    add_heading(document, "ГЛАВА 1 АНАЛИЗ СРЕДСТВ АВТОМАТИЗАЦИИ САЛОНОВ КРАСОТЫ", main=True)
    add_heading(document, "1.1 Особенности автоматизации записи клиентов салона красоты")
    for paragraph in CHAPTER_11:
        add_body_paragraph(document, paragraph)

    add_heading(document, "1.2 Сравнительный анализ существующих решений")
    for paragraph in CHAPTER_12:
        add_body_paragraph(document, paragraph)

    add_table_title(document, "Таблица 1 — Сравнительная характеристика существующих решений")
    table = document.add_table(rows=1, cols=len(TABLE_HEADERS))
    table.alignment = WD_TABLE_ALIGNMENT.CENTER
    table.style = "Table Grid"
    for cell, header in zip(table.rows[0].cells, TABLE_HEADERS):
        format_cell(cell, header, bold=True)
    for row_data in TABLE_ROWS:
        row = table.add_row().cells
        for cell, value in zip(row, row_data):
            format_cell(cell, value)

    add_body_paragraph(
        document,
        "Данные таблицы подтверждают, что готовые решения покрывают либо широкий круг задач ценой избыточности и высокой стоимости, либо обеспечивают только поверхностную автоматизацию без полноценной CRM-логики. Поэтому разработка специализированной системы для конкретного салона красоты является рациональным компромиссом между функциональностью, стоимостью и гибкостью настройки.",
    )

    add_heading(document, "1.3 Архитектура VK API и выбор технологий разработки")
    for paragraph in CHAPTER_13:
        add_body_paragraph(document, paragraph)

    add_heading(document, "Выводы по главе 1")
    for paragraph in CHAPTER_CONCLUSION:
        add_body_paragraph(document, paragraph)

    return document


